        "remote and irrelevant alien":          { section:"reading", ipa:"/ɪˈrel.ə.vənt/", stressed:"Re", meaning:"sinh vật xa lạ, nhỏ bé và không đáng kể", type:"phrase", collocation:"a remote and irrelevant creature", example:"From the perspective of the universe, every explorer is a remote and irrelevant alien on an unremarkable planet.", connotation:"negative" },
        "puny and irrelevant alien crawling laboriously": { section:"reading", ipa:"/ləˈbɔː.ri.əs.li/", stressed:"Bor", meaning:"sinh vật nhỏ bé vô nghĩa bò lê một cách khó nhọc", type:"phrase", collocation:"a puny creature crawling laboriously", example:"Critics of space exploration see humans as a puny and irrelevant alien crawling laboriously across an indifferent cosmos.", connotation:"negative" },
        "confined myself to":                   { section:"reading", ipa:"/kənˈfaɪnd/", stressed:"Faind", meaning:"giới hạn bản thân trong phạm vi", type:"phrase", collocation:"confined myself to real examples", example:"In writing this book, I have confined myself to those whose travels were real, not imagined.", connotation:"neutral" },
        "has become associated with a past era": { section:"reading", ipa:"/əˈsəʊ.si.eɪ.tɪd/", stressed:"Sou", meaning:"đã trở nên gắn liền với một thời đại đã qua", type:"phrase", collocation:"exploration associated with a past era", example:"For many people, the word 'exploration' has become associated with a past era of pith helmets and compasses.", connotation:"neutral" },
        "dubbed":                               { section:"reading", ipa:"/dʌbd/", stressed:"Dubbed", meaning:"được mệnh danh, được gọi là", type:"verb", collocation:"dubbed the greatest explorer", example:"He has been dubbed the greatest living explorer by the Royal Geographical Society.", connotation:"neutral" },
        "scientifically useful":                { section:"reading", ipa:"/ˌsaɪ.ənˈtɪf.ɪ.kəl.i/", stressed:"Ti", meaning:"có ích cho khoa học", type:"adjective", collocation:"exploration must be scientifically useful", example:"Modern expeditions are expected to be scientifically useful, not merely adventurous.", connotation:"positive" },
        "campaigner on behalf of remote peoples": { section:"reading", ipa:"/kæmˈpeɪ.nər/", stressed:"Pei", meaning:"người vận động cho quyền lợi của các dân tộc vùng xa", type:"phrase", collocation:"a tireless campaigner on behalf of", example:"She became a prominent campaigner on behalf of remote peoples whose lands were being destroyed by logging.", connotation:"positive" },
        "field of endeavour":                   { section:"reading", ipa:"/ɪnˈdev.ər/", stressed:"De", meaning:"lĩnh vực hoạt động / nỗ lực", type:"phrase", collocation:"in every field of endeavour", example:"True explorers push boundaries in every field of endeavour, from science to the arts.", connotation:"positive" },
        "cutting-edge scientist":               { section:"reading", ipa:"/ˌkʌt.ɪŋˈedʒ/", stressed:"Edge", meaning:"nhà khoa học tiên phong", type:"phrase", collocation:"a cutting-edge scientist in the field", example:"She is a cutting-edge scientist whose work on gene therapy has attracted global attention.", connotation:"positive" },
        "from the outset":                      { section:"reading", ipa:"/ˈaʊt.set/", stressed:"Out", meaning:"ngay từ đầu", type:"phrase", collocation:"clear from the outset", example:"The expedition had a very definite objective from the outset: to map the entire cave system.", connotation:"neutral" },
        "bias":                                 { section:"reading", ipa:"/ˈbaɪ.əs/", stressed:"Bai", meaning:"sự thiên lệch, thành kiến", type:"noun", antonym:"objectivity", collocation:"declare one's own bias", example:"I should declare my own bias: I believe exploration still matters in the modern world.", connotation:"neutral" },
        "a new slant":                          { section:"reading", ipa:"/slɑːnt/", stressed:"Slant", meaning:"một góc nhìn mới", type:"phrase", collocation:"find a new slant on a topic", example:"Every good journalist tries to find a new slant on a story that has already been widely covered.", connotation:"positive" },
        "fresh interpretation":                 { section:"reading", ipa:"/ɪnˌtɜː.prɪˈteɪ.ʃən/", stressed:"Tei", meaning:"cách diễn giải mới mẻ", type:"phrase", collocation:"offer a fresh interpretation of", example:"The historian offered a fresh interpretation of a well-travelled route through Central Asia.", connotation:"positive" },
